import React from 'react';

class Header extends React.Component {
    render() {
         return (
             <div className="Header">
                 <header className="header" id="header">
                        <div className="container">
                            <div className="header_inner">
                                <a className="logo" href="#" data-scroll="#main_section">MoGo</a>
                                <nav className="nav" id="nav">
                                    <a className="nav_link" href="#" data-scroll="#about">About</a>
                                    <a className="nav_link" href="#" data-scroll="#services">Service</a>
                                    <a className="nav_link" href="#" data-scroll="#blog">Blog</a>
                                    <a className="nav_link" href="#" data-scroll="#work">Work</a>
                                    <a className="nav_link" href="#" data-scroll="#contact">Contact</a>
                                    <a className="nav_link"><i className="fa-solid fa-cart-shopping" href="#"></i></a>
                                    <a className="nav_link"><i className="fa-solid fa-magnifying-glass" href="#"></i></a>
                                </nav>

                                <button className="nav_toggle" type="menu" id="nav_toggle">
                                    <i className="fa-solid fa-bars"></i>
                                </button>
                            </div>
                        </div>
                 </header>
             </div>
            );
        }
}

export default Header;
